import{_ as e,o as s,c as t,ag as o}from"./chunks/framework.Bgwu_dgr.js";const g=JSON.parse('{"title":"점진적 공개","description":"","frontmatter":{},"headers":[],"relativePath":"topics/progressive-disclosure.md","filePath":"topics/progressive-disclosure.md","lastUpdated":null}'),r={name:"topics/progressive-disclosure.md"};function i(n,a,l,p,h,d){return s(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="점진적-공개" tabindex="-1">점진적 공개 <a class="header-anchor" href="#점진적-공개" aria-label="Permalink to &quot;점진적 공개&quot;">​</a></h1><p>스킬의 아이디어를 듣고 나면 자연스러운 질문이 떠오른다. <strong>&quot;그럼 에이전트가 수백, 수천 개의 스킬을 가지면 컨텍스트 윈도우가 폭발하지 않나?&quot;</strong> 이 질문에 대한 답이 스킬의 가장 중요한 엔지니어링 설계인 **점진적 공개(Progressive Disclosure)**다.</p><h2 id="_3단계의-정보-공개" tabindex="-1">3단계의 정보 공개 <a class="header-anchor" href="#_3단계의-정보-공개" aria-label="Permalink to &quot;3단계의 정보 공개&quot;">​</a></h2><p>점진적 공개는 스킬의 정보를 <strong>세 단계로 나누어</strong> 컨텍스트에 투입하는 설계다.</p><h3 id="level-1-메타데이터-시스템-프롬프트에-상주" tabindex="-1">Level 1 -- 메타데이터 (시스템 프롬프트에 상주) <a class="header-anchor" href="#level-1-메타데이터-시스템-프롬프트에-상주" aria-label="Permalink to &quot;Level 1 -- 메타데이터 (시스템 프롬프트에 상주)&quot;">​</a></h3><p>에이전트의 시스템 프롬프트에 노출되는 것은 <strong>각 스킬의 이름과 짧은 설명</strong>뿐이다. <code>SKILL.md</code>의 YAML 프론트매터에서 추출되는 정보다.</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">invoice-processing</span></span>\n<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">사내 표준 양식의 송장을 읽고 회계 시스템에 맞게 변환·검증하는 절차</span></span></code></pre></div><p>수백 개의 스킬이 있어도 이 메타데이터만 합치면 몇 KB를 넘지 않는다. 에이전트는 이 목록을 보고 <strong>지금 상황에 어떤 스킬이 관련되는지</strong>를 판단한다.</p><h3 id="level-2-skill-md-본문-필요-시-로드" tabindex="-1">Level 2 -- <code>SKILL.md</code> 본문 (필요 시 로드) <a class="header-anchor" href="#level-2-skill-md-본문-필요-시-로드" aria-label="Permalink to &quot;Level 2 -- `SKILL.md` 본문 (필요 시 로드)&quot;">​</a></h3><p>에이전트가 특정 스킬이 유용하다고 판단하면, 그때 비로소 해당 스킬의 <code>SKILL.md</code> 본문 전체를 컨텍스트로 불러온다. 절차의 단계, 주의 사항, 엣지 케이스 처리법 등이 여기에 담긴다.</p><p>이 시점에서도 아직 스크립트나 참조 문서는 로드되지 않는다. **&quot;이 스킬을 실제로 써야겠다&quot;**가 확정된 지식 수준까지만 올라와 있다.</p><h3 id="level-3-참조-파일과-스크립트-순간적으로" tabindex="-1">Level 3 -- 참조 파일과 스크립트 (순간적으로) <a class="header-anchor" href="#level-3-참조-파일과-스크립트-순간적으로" aria-label="Permalink to &quot;Level 3 -- 참조 파일과 스크립트 (순간적으로)&quot;">​</a></h3><p>작업이 실제로 실행될 때, 에이전트는 스킬 폴더 안의 스크립트를 실행하거나 참조 문서를 읽는다. 그러나 <strong>이 내용이 전부 컨텍스트에 영구 상주하지는 않는다.</strong> 실행되면 출력만 남고, 참조 문서는 필요한 조각만 읽힌다.</p><p>이렇게 하면 수천 개의 스킬이 있어도 <strong>실제로 활성화된 맥락</strong>만 컨텍스트에 있다. 나머지는 파일 시스템에서 조용히 대기한다.</p><h2 id="왜-이-구조가-중요한가" tabindex="-1">왜 이 구조가 중요한가 <a class="header-anchor" href="#왜-이-구조가-중요한가" aria-label="Permalink to &quot;왜 이 구조가 중요한가&quot;">​</a></h2><p>점진적 공개의 효과는 단순히 &quot;토큰 절약&quot;을 넘어선다. 세 가지 효과가 동시에 나타난다.</p><p><strong>1. 확장성</strong><br> 조직이 추가하는 스킬의 수가 100개, 1000개로 늘어나도 에이전트는 느려지지 않는다. 시스템 프롬프트의 크기는 거의 일정하게 유지된다.</p><p><strong>2. 집중력</strong><br> 무관한 정보가 컨텍스트에 섞이면 모델은 혼란스러워진다. 점진적 공개는 <strong>지금 작업에 필요한 지식만</strong> 모델에 보여줌으로써, 판단의 품질을 높인다.</p><p><strong>3. 비용</strong><br> 각 호출에 들어가는 토큰이 줄면 지연도 줄고 비용도 준다. 대규모 엔터프라이즈 배포에서 이 차이는 작지 않다.</p><h2 id="os의-가상-메모리와의-유비" tabindex="-1">OS의 가상 메모리와의 유비 <a class="header-anchor" href="#os의-가상-메모리와의-유비" aria-label="Permalink to &quot;OS의 가상 메모리와의 유비&quot;">​</a></h2><p>Zhang과 Murag은 이 설계를 운영체제의 메모리 계층에 비유한다. 운영체제는 모든 프로그램을 RAM에 올려두지 않는다. 필요할 때 디스크에서 페이지를 로드하고, 쓰지 않는 페이지는 내려놓는다.</p><p>에이전트의 컨텍스트 윈도우는 <strong>값비싼 RAM</strong>이다. 스킬의 파일 시스템 전체는 <strong>디스크</strong>다. 점진적 공개는 둘 사이의 <strong>페이징(paging)</strong> 메커니즘에 해당한다. 이 유비는 우연이 아니다. 발표 후반부에서 &quot;에이전트 런타임은 일종의 운영체제다&quot;라는 주장이 등장하는데, 점진적 공개는 그 주장의 구체적 근거 중 하나다.</p><h2 id="스킬-간의-구성-트리거와-조합" tabindex="-1">스킬 간의 구성 -- 트리거와 조합 <a class="header-anchor" href="#스킬-간의-구성-트리거와-조합" aria-label="Permalink to &quot;스킬 간의 구성 -- 트리거와 조합&quot;">​</a></h2><p>점진적 공개는 또 하나의 효과를 낳는다. <strong>스킬이 다른 스킬을 불러올 수 있게</strong> 된다. 복잡한 작업에서는 하나의 스킬이 다른 스킬의 메타데이터를 언급하거나, 스크립트 안에서 다른 스킬의 기능을 호출한다.</p><p>이것은 소프트웨어 공학에서 **모듈의 합성(composition)**이라 부르는 원리다. 각 스킬은 작고 독립적이되, 조합하면 큰 작업을 수행할 수 있다. 그리고 각 스킬은 필요한 순간에만 로드되기 때문에, 합성의 깊이가 깊어져도 컨텍스트가 터지지 않는다.</p><h2 id="설계가-준-교훈" tabindex="-1">설계가 준 교훈 <a class="header-anchor" href="#설계가-준-교훈" aria-label="Permalink to &quot;설계가 준 교훈&quot;">​</a></h2><p>점진적 공개의 가장 큰 가치는 **&quot;작은 것이 많이 있는 상태&quot;**를 실용적으로 만들었다는 점이다. 에이전트 업계의 초기 본능은 &quot;하나의 큰 프롬프트&quot;였다. 모든 맥락과 규칙을 한 번에 주입하려는 시도다. 그 방향의 한계가 드러난 지금, 대안은 <strong>작은 단위의 지식 조각들을 지능적으로 로드/언로드</strong>하는 것이다.</p><p>스킬 + 점진적 공개는 이 대안의 구체적인 구현이다. 그리고 이 설계는 다시 스킬 생태계 -- 수천 개의 작고 독립적인 단위가 공존할 수 있는 환경 -- 을 가능하게 만들었다.</p><blockquote><p>점진적 공개는 컨텍스트를 지킨다. 그리고 컨텍스트가 지켜지면, 스킬은 끝없이 많을 수 있다.</p></blockquote>',29)])])}const u=e(r,[["render",i]]);export{g as __pageData,u as default};
